# Module demonstrating cross-module inheritance and interface implementation
from core_types import Status, IIdentifiable, IStatusTrackable, ILogger, Entity

class Task(Entity, IIdentifiable, IStatusTrackable):
    status: Status
    priority: int

    def __init__(self, id: int, name: str, priority: int):
        super().__init__(id, name)
        self.status = Status.PENDING
        self.priority = priority

    @override
    def describe(self) -> str:
        return f"Task[{self.status}]: {self.name} (P{self.priority})"

    def get_status(self) -> Status:
        return self.status

    def set_status(self, new_status: Status) -> None:
        self.status = new_status

    def get_id(self) -> int:
        return self.id

class ConsoleLogger(ILogger):
    prefix: str

    def __init__(self, prefix: str):
        self.prefix = prefix

    def log(self, message: str) -> None:
        print(f"[{self.prefix}] {message}")

class PriorityTask(Task):
    is_urgent: bool

    def __init__(self, id: int, name: str, priority: int, urgent: bool):
        super().__init__(id, name, priority)
        self.is_urgent = urgent

    @override
    def describe(self) -> str:
        base: str = super().describe()
        if self.is_urgent:
            return f"URGENT {base}"
        return base

