# Utility module with helpers, enums, and structures
from core_types import Dimension

enum LogLevel:
    DEBUG = 0
    INFO = 1
    WARN = 2
    ERROR = 3

class MathHelper:
    @static
    def clamp(value: int, min_val: int, max_val: int) -> int:
        if value < min_val:
            return min_val
        if value > max_val:
            return max_val
        return value

    @static
    def scale_dimension(dim: Dimension, factor: float) -> Dimension:
        return Dimension(dim.width * factor, dim.height * factor)

def format_status(status: Status) -> str:
    if status == Status.PENDING:
        return "PENDING"
    elif status == Status.ACTIVE:
        return "ACTIVE"
    elif status == Status.COMPLETED:
        return "COMPLETED"
    elif status == Status.FAILED:
        return "FAILED"
    else:
        return "UNKNOWN"
